#include "interface.h"
#include <cstdint>
#include <vector>
#include <string>

namespace {

inline bool matches_prefix(const std::string& s) {
    return s[0] == 'q' && s[1] <= 'm';
}

}  // namespace

uint64_t dictionary_prefix_weight_sum(
    const std::vector<std::string>& dictionary,
    const std::vector<uint16_t>& codes,
    const std::vector<uint32_t>& weights,
    int iters) {

    // Pre-compute once which dictionary entries satisfy the prefix rule
    std::vector<uint8_t> prefix_ok(dictionary.size(), 0);
    for (size_t idx = 0; idx < dictionary.size(); ++idx) {
        prefix_ok[idx] = matches_prefix(dictionary[idx]);
    }

    uint64_t sum = 0;
    for (int iter = 0; iter < iters; ++iter) {
        sum = 0;
        const size_t n = codes.size();
        for (size_t i = 0; i < n; ++i) {
            const uint16_t code = codes[i];
            if (__builtin_expect(prefix_ok[code], 0)) {
                sum += static_cast<uint64_t>(weights[i]);
            }
        }
    }
    return sum;
}
